import{_ as i,o as a,c as t,a0 as r}from"./chunks/framework.AQcSKqPn.js";const f=JSON.parse('{"title":"Project Overview","description":"","frontmatter":{"type":"overview","title":"Project Overview","tags":[],"related":["sousou-no-frieren","frieren","long-lived-time-perception","post-adventure-narrative","re-zero-4th-season","subaru-natsuki","rem","authority-of-gluttony","pleiades-watchtower","sage-shaula","fullmetal-alchemist-brotherhood","edward-elric","alphonse-elric","human-transmutation","equivalent-exchange","steel-ball-run","steel-ball-run-race","steins-gate","rintarou-okabe","mayuri-shiina","itaru-hashida","future-gadget-laboratory","chainsaw-man-reze-movie","denji","makima","reze","devil-hunter","shingeki-no-kyojin","eren-yeager","survey-corps","wall-maria","shiganshina-district","armin-arlert","wall-maria-retaking","titan-absence","gintama","gintoki-sakata","shinpachi-shimura","kagura","yorozuya","alternate-history-edo","utsuro","tendoshuu","shinsengumi","altana","hunter-x-hunter-2011","gon-freecss","ging-freecss","hunter-examination","hunter"]},"headers":[],"relativePath":"overview.md","filePath":"overview.md","lastUpdated":1783992263000}'),n={name:"overview.md"};function l(s,e,o,h,m,u){return a(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h1><p>本Wiki当前聚焦于对十部日本动画作品的分析与知识组织：《葬送的芙莉莲》（Sousou no Frieren）、《Re:Zero kara Hajimeru Isekai Seikatsu 4th Season》、《钢之炼金术师 FULLMETAL ALCHEMIST》（Fullmetal Alchemist: Brotherhood）、《Steel Ball Run: JoJo no Kimyou na Bouken》（Steel Ball Run: JoJo&#39;s Bizarre Adventure）、《Steins;Gate》（命运石之门）、《Chainsaw Man Movie: Reze-hen》（电锯人 蕾塞篇）、《Shingeki no Kyojin Season 3 Part 2》（进击的巨人 第三季 Part 2）、《Gintama°》（银魂°）、《Gintama: The Very Final》（银魂：最终篇）以及《Hunter x Hunter (2011)》。</p><p>《葬送的芙莉莲》是一部2023年播出的日本动画（改编自同名漫画），在MyAnimeList上获得9.26的极高评分，以其叙事创新性和情感深度而备受赞誉。Wiki收录了作品实体页面（<a href="/llm-wiki/entities/sousou-no-frieren">sousou-no-frieren</a>）与核心角色页面（<a href="/llm-wiki/entities/frieren-芙莉莲">frieren</a>），并提炼出两个跨作品适用的核心概念：<a href="/llm-wiki/concepts/长寿种的时间感知-long-lived-time-perception">long-lived-time-perception</a>——探讨寿命差异带来的时间体验与情感鸿沟；以及<a href="/llm-wiki/concepts/冒险后的叙事-post-adventure-narrative">post-adventure-narrative</a>——一种以冒险结束为起点的叙事结构。</p><p>《Re:Zero》第四季是2026年播出的动画，在MyAnimeList上获得9.18的评分。本季故事始于水门都市普利斯特拉的惨胜之后，主角<a href="/llm-wiki/entities/菜月昴-subaru-natsuki">subaru-natsuki</a>的同伴被&quot;暴食&quot;权能（<a href="/llm-wiki/concepts/暴食权能-authority-of-gluttony">authority-of-gluttony</a>）吞噬了存在，他因此踏上寻找全知&quot;贤者&quot;莎缇拉（<a href="/llm-wiki/entities/贤者莎缇拉-sage-shaula">sage-shaula</a>）的旅程，前往贤者之塔（<a href="/llm-wiki/entities/贤者之塔-pleiades-watchtower">pleiades-watchtower</a>）。Wiki收录了作品实体页面（<a href="/llm-wiki/entities/re-zero-4th-season">re-zero-4th-season</a>）、核心角色页面（<a href="/llm-wiki/entities/菜月昴-subaru-natsuki">subaru-natsuki</a>、<a href="/llm-wiki/entities/雷姆-rem">rem</a>、<a href="/llm-wiki/entities/贤者莎缇拉-sage-shaula">sage-shaula</a>）、关键地点页面（<a href="/llm-wiki/entities/贤者之塔-pleiades-watchtower">pleiades-watchtower</a>）以及核心概念页面（<a href="/llm-wiki/concepts/暴食权能-authority-of-gluttony">authority-of-gluttony</a>）。</p><p>《钢之炼金术师 FULLMETAL ALCHEMIST》是2009年播出的动画，在MyAnimeList上获得9.11的评分，被广泛认为是有史以来最伟大的动画之一。故事围绕艾尔利克兄弟——<a href="/llm-wiki/entities/爱德华艾尔利克">edward-elric</a>和<a href="/llm-wiki/entities/阿尔冯斯艾尔利克">alphonse-elric</a>——因尝试禁忌的<a href="/llm-wiki/concepts/人体炼成">human-transmutation</a>而付出惨痛代价展开。Wiki收录了作品实体页面（<a href="/llm-wiki/entities/钢之炼金术师-fullmetal-alchemist">fullmetal-alchemist-brotherhood</a>）、核心角色页面（<a href="/llm-wiki/entities/爱德华艾尔利克">edward-elric</a>、<a href="/llm-wiki/entities/阿尔冯斯艾尔利克">alphonse-elric</a>）以及核心概念页面（<a href="/llm-wiki/concepts/人体炼成">human-transmutation</a>、<a href="/llm-wiki/concepts/等价交换">equivalent-exchange</a>）。</p><p>《Steel Ball Run: JoJo no Kimyou na Bouken》是《JoJo的奇妙冒险》系列的一部动画作品，于2026年播出，在MyAnimeList上获得9.1的高评分，目前状态为&quot;Currently Airing&quot;。故事设定在美国旧西部，一场名为&quot;Steel Ball Run&quot;的跨国越野赛成为核心舞台，参赛者从圣地亚哥出发穿越超过六千公里的荒野争夺巨额奖金。Wiki收录了作品实体页面（<a href="/llm-wiki/entities/steel-ball-run">steel-ball-run</a>）以及赛事概念页面（<a href="/llm-wiki/concepts/steel-ball-run-赛事">steel-ball-run-race</a>）。</p><p>《Steins;Gate》是2011年播出的科幻悬疑动画，在MyAnimeList上获得9.07的极高评分，被广泛认为是科幻动画的经典之作。故事围绕疯狂科学家<a href="/llm-wiki/entities/rintarou-okabe">rintarou-okabe</a>展开，他与朋友<a href="/llm-wiki/entities/mayuri-shiina">mayuri-shiina</a>和<a href="/llm-wiki/entities/itaru-hashida">itaru-hashida</a>共同创立了<a href="/llm-wiki/entities/future-gadget-laboratory">future-gadget-laboratory</a>，发明了一台能够操控时间的微波炉装置。Wiki收录了作品实体页面（<a href="/llm-wiki/entities/steins-gate">steins-gate</a>）、核心角色页面（<a href="/llm-wiki/entities/rintarou-okabe">rintarou-okabe</a>、<a href="/llm-wiki/entities/mayuri-shiina">mayuri-shiina</a>、<a href="/llm-wiki/entities/itaru-hashida">itaru-hashida</a>）以及组织设定页面（<a href="/llm-wiki/entities/future-gadget-laboratory">future-gadget-laboratory</a>）。</p><p>《Chainsaw Man Movie: Reze-hen》是2025年上映的动画电影，在MyAnimeList上获得9.06的高评分。故事围绕<a href="/llm-wiki/entities/denji">denji</a>在成为公安对魔特异课的<a href="/llm-wiki/concepts/恶魔猎人-devil-hunter">devil-hunter</a>后展开，精英恶魔猎人<a href="/llm-wiki/entities/makima">makima</a>通过约会对他进行情感操控，而看似无辜的咖啡馆女服务员<a href="/llm-wiki/entities/reze">reze</a>的出现则使Denji陷入情感三角冲突。Wiki收录了作品实体页面（<a href="/llm-wiki/entities/chainsaw-man-reze-movie">chainsaw-man-reze-movie</a>）、核心角色页面（<a href="/llm-wiki/entities/denji">denji</a>、<a href="/llm-wiki/entities/makima">makima</a>、<a href="/llm-wiki/entities/reze">reze</a>）以及核心概念页面（<a href="/llm-wiki/concepts/恶魔猎人-devil-hunter">devil-hunter</a>）。</p><p>《Shingeki no Kyojin Season 3 Part 2》（进击的巨人 第三季 Part 2）是2019年播出的动画，在MyAnimeList上获得9.05的高评分。本季讲述了<a href="/llm-wiki/entities/survey-corps-调查兵团">survey-corps</a>为夺回<a href="/llm-wiki/entities/wall-maria-玛利亚之墙">wall-maria</a>而发起的希干希纳区战役，<a href="/llm-wiki/entities/eren-yeager-艾伦耶格尔">eren-yeager</a>返回故乡却发现巨人异常缺席，这一悬念由<a href="/llm-wiki/entities/armin-arlert-阿明阿诺德">armin-arlert</a>提出，成为本季的关键叙事转折点。Wiki收录了来源页面（<a href="/llm-wiki/sources/5-anime--5-38524--hnv61b">5-anime--5-38524--hnv61b</a>）、系列实体页面（<a href="/llm-wiki/entities/shingeki-no-kyojin">shingeki-no-kyojin</a>）、核心角色页面（<a href="/llm-wiki/entities/eren-yeager-艾伦耶格尔">eren-yeager</a>、<a href="/llm-wiki/entities/armin-arlert-阿明阿诺德">armin-arlert</a>）、组织页面（<a href="/llm-wiki/entities/survey-corps-调查兵团">survey-corps</a>）、地点页面（<a href="/llm-wiki/entities/wall-maria-玛利亚之墙">wall-maria</a>、<a href="/llm-wiki/entities/shiganshina-district-希干希纳区">shiganshina-district</a>）以及概念页面（<a href="/llm-wiki/concepts/夺回玛利亚之墙">wall-maria-retaking</a>、<a href="/llm-wiki/concepts/巨人的缺席">titan-absence</a>）。</p><p>《Gintama°》（银魂°）是《银魂》系列的第四季动画，于2015年播出，共51集，在MyAnimeList上获得9.05的高评分。故事发生在一个被外星人（天人）征服、禁刀的架空江户时代，主角<a href="/llm-wiki/entities/坂田银时-gintoki-sakata">gintoki-sakata</a>、<a href="/llm-wiki/entities/志村新八-shinpachi-shimura">shinpachi-shimura</a>和<a href="/llm-wiki/entities/神乐-kagura">kagura</a>三人经营着万事屋（<a href="/llm-wiki/entities/万事屋-yorozuya">yorozuya</a>），靠接各种零活维生。该作品以其独特的<a href="/llm-wiki/concepts/架空历史江户设定-alternate-history-edo">alternate-history-edo</a>、无厘头喜剧与感人剧情并存的风格而闻名。</p><p>《Gintama: The Very Final》（银魂：最终篇）是《银魂》系列的最终章电影，于2021年上映，在MyAnimeList上获得9.05的高评分。故事发生在<a href="/llm-wiki/entities/天道众-tendoshuu">tendoshuu</a>入侵O-Edo Central Terminal两年后，<a href="/llm-wiki/entities/万事屋-yorozuya">yorozuya</a>成员已分道扬镳，<a href="/llm-wiki/entities/坂田银时-gintoki-sakata">gintoki-sakata</a>预见到<a href="/llm-wiki/entities/虚-utsuro">utsuro</a>的回归，开始勘测地球的龙脉（<a href="/llm-wiki/concepts/阿尔塔纳-altana">altana</a>）以追踪虚的踪迹。重组后的<a href="/llm-wiki/entities/真选组-shinsengumi">shinsengumi</a>与万事屋联手对被占领的Central Terminal发起进攻。Wiki收录了来源页面（<a href="/llm-wiki/sources/5-anime--5-39486--1xtfkzd">5-anime--5-39486--1xtfkzd</a>）、作品实体页面（<a href="/llm-wiki/entities/gintama-银魂">gintama</a>）、核心角色页面（<a href="/llm-wiki/entities/坂田银时-gintoki-sakata">gintoki-sakata</a>）、组织页面（<a href="/llm-wiki/entities/万事屋-yorozuya">yorozuya</a>、<a href="/llm-wiki/entities/真选组-shinsengumi">shinsengumi</a>、<a href="/llm-wiki/entities/天道众-tendoshuu">tendoshuu</a>）、反派页面（<a href="/llm-wiki/entities/虚-utsuro">utsuro</a>）以及概念页面（<a href="/llm-wiki/concepts/阿尔塔纳-altana">altana</a>）。</p><p>《Hunter x Hunter (2011)》是一部由Madhouse制作的动画作品，于2011年至2014年播出，共148集，在MyAnimeList上获得9.03的高评分。故事围绕猎人这一职业展开，猎人们致力于完成探索未知领域、寻找稀有物品等危险任务。成为猎人的必经之路是<a href="/llm-wiki/concepts/猎人考试-hunter-examination">hunter-examination</a>——一个高风险、高淘汰率的选拔过程。12岁的<a href="/llm-wiki/entities/gon-freecss-小杰富力士">gon-freecss</a>参加猎人考试的驱动力是寻找他的父亲<a href="/llm-wiki/entities/ging-freecss-金富力士">ging-freecss</a>——一名猎人。Wiki收录了作品实体页面（<a href="/llm-wiki/entities/hunter-x-hunter-2011">hunter-x-hunter-2011</a>）、核心角色页面（<a href="/llm-wiki/entities/gon-freecss-小杰富力士">gon-freecss</a>、<a href="/llm-wiki/entities/ging-freecss-金富力士">ging-freecss</a>）以及核心概念页面（<a href="/llm-wiki/concepts/猎人考试-hunter-examination">hunter-examination</a>、<a href="/llm-wiki/concepts/猎人-hunter">hunter</a>）。</p><p>当前Wiki处于早期建设阶段，以十部作品为起点，提炼出跨作品适用的叙事与主题分析框架。未来可扩展至更多相关作品、叙事理论及主题分析。来源页面提供了作品的元数据与剧情摘要，作为所有分析的基础依据。</p>',13)])])}const w=i(n,[["render",l]]);export{f as __pageData,w as default};
